// GET Search endpoint (FRICTIONLESS_SPEC.md section 4.1 - Legacy GET support)
// Accepts query param ?q=... for simple searches, supports ?limit, ?tags, ?buckets
app.get('/v1/search', async (req: Request, res: Response) => {
  const startTime = Date.now();
  const queryParam = req.query.q as string;

  if (!queryParam) {
    StructuredLogger.info('GET_SEARCH_NO_QUERY', {
      url: req.url,
    });
    return res.status(400).json({ error: 'Query parameter "q" is required' });
  }

  // Parse additional query params
  const limitParam = req.query.limit ? parseInt(req.query.limit as string, 10) : 10;
  const tagsParam = req.query.tags ? (req.query.tags as string).split(',').map(t => t.trim()) : [];
  const bucketsParam = req.query.buckets ? (req.query.buckets as string).split(',').map(b => b.trim()) : [];
  const maxChars = 2400; // Default mobile-friendly budget for simple GET searches

  StructuredLogger.info('GET_SEARCH_REQUEST', {
    query: queryParam.substring(0, 100),
    limit: limitParam,
    tags: tagsParam,
    buckets: bucketsParam,
    maxChars,
  });

  try {
    // Execute search using the standard smartChatSearch function
    const searchResult = await smartChatSearch(
      queryParam,
      bucketsParam,
      maxChars,
      tagsParam,
      'all', // provenance
      false, // useMaxRecall = false (standard for simple queries)
      undefined, // user_context
    );

    const duration = Date.now() - startTime;

    // Format results with content (FRICTIONLESS_SPEC.md section 4.1)
    const formattedResults = searchResult.results.map(r => ({
      uuid: r.id,
      content: r.content,
      source: r.source,
      timestamp: new Date(r.timestamp).toISOString(),
      score: r.score,
      tags: r.tags || [],
      buckets: r.buckets || [],
      provenance: r.provenance,
      compound_id: r.compound_id,
      start_byte: r.start_byte,
      end_byte: r.end_byte,
    }));

    // Respect limit parameter
    const limitedResults = limitParam > 0 ? formattedResults.slice(0, limitParam) : formattedResults;

    const response: any = {
      status: 'success',
      metadata: {
        totalResults: formattedResults.length,
        durationMs: duration,
        strategy: searchResult.strategy,
        query: queryParam,
        tags: tagsParam,
        buckets: bucketsParam,
      },
      results: limitedResults,
    };

    StructuredLogger.info('GET_SEARCH_COMPLETE', {
      query: queryParam.substring(0, 100),
      totalResults: formattedResults.length,
      resultsReturned: limitedResults.length,
      durationMs: duration,
    });

    res.status(200).json(response);
  } catch (error: any) {
    const duration = Date.now() - startTime;
    StructuredLogger.error('GET_SEARCH_ERROR', error, {
      query: queryParam.substring(0, 100),
      durationMs: duration,
    });

    if (!res.headersSent) {
      res.status(500).json({
        error: 'Internal server error during search',
        details: error.message,
      });
    }
  }
});

